    font-size: 0.8rem;
}

.appearance-preview.preview-large {
    font-size: 1.15rem;
}

.appearance-preview.preview-compact {
    padding: 0.5rem;
    line-height: 1.25;
}

.preview-header {
    font-weight: 600;
    margin-bottom: 0.5rem;
}
