toolArgs.file_text:
@page "/settings"
@rendermode InteractiveServer
@using sv_e246ce6d89e542118f2399c8e80928b6.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="@(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => ActiveSection = section.Key">
                    <span class="nav-icon">@section.Icon</span>
                    <span>@section.Label</span>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center p-5"><div class="spinner-border" role="status"></div></div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        @if (!string.IsNullOrEmpty(_toastMessage))
        {
            <div class="toast-message @(_toastIsError ? "toast-error" : "toast-success")">
                @_toastMessage
            </div>
        }
    </div>
</div>

@* ───── Confirmation modal ───── *@
@if (_showConfirmDialog)
{
    <div class="modal-backdrop" @onclick="() => _showConfirmDialog = false"></div>
    <div class="confirm-dialog">
        <h6>Revoke Session</h6>
        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke?.Device</strong>?</p>
        <div class="d-flex gap-2 justify-content-end">
            <button class="btn btn-sm btn-secondary" @onclick="() => _showConfirmDialog = false">Cancel</button>
            <button class="btn btn-sm btn-danger" @onclick="ConfirmRevokeSession">Revoke</button>
        </div>
    </div>
}

@* ───── PROFILE ───── *@
@{
    RenderFragment RenderProfileSection() =>
        @<section>
            <h4>Profile</h4>
            <div class="settings-card">
                <div class="avatar-area mb-3">
                    <img src="@_editProfile!.AvatarUrl" alt="Avatar" class="avatar-preview" />
                    <small class="text-muted d-block mt-1">@_editProfile.AvatarUrl</small>
                </div>

                <div class="mb-3">
                    <label class="form-label">Display Name</label>
                    <input class="form-control" @bind="_editProfile.DisplayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email</label>
                    <input class="form-control" type="email" @bind="_editProfile.Email" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="3" @bind="_editProfile.Bio"></textarea>
                </div>

                <div class="d-flex gap-2">
                    <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
                    <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
                </div>
            </div>
        </section>;
}

@* ───── NOTIFICATIONS ───── *@
@{
    RenderFragment RenderNotificationsSection() =>
        @<section>
            <h4>Notifications</h4>
            <div class="settings-card">
                <div class="toggle-row">
                    <label>Email Notifications</label>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@_editNotifications!.EmailNotifications"
                               @onchange="e => _editNotifications.EmailNotifications = (bool)e.Value!" />
                    </div>
                </div>
                <div class="toggle-row">
                    <label>Push Notifications</label>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@_editNotifications.PushNotifications"
                               @onchange="e => _editNotifications.PushNotifications = (bool)e.Value!" />
                    </div>
                </div>
                <div class="toggle-row">
                    <label>Weekly Digest</label>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@_editNotifications.WeeklyDigest"
                               @onchange="e => _editNotifications.WeeklyDigest = (bool)e.Value!" />
                    </div>
                </div>

                <hr />
                <h6>Muted Channels</h6>
                @foreach (var channel in _allChannels)
                {
                    var isMuted = _editNotifications.MutedChannels.Contains(channel);
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@isMuted"
                               @onchange="e => ToggleMutedChannel(channel, (bool)e.Value!)" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }

                <button class="btn btn-primary mt-3" @onclick="SaveNotifications">Save Preferences</button>
            </div>
        </section>;
}

@* ───── SECURITY ───── *@
@{
    RenderFragment RenderSecuritySection() =>
        @<section>
            <h4>Security</h4>

            @* Change Password *@
            <div class="settings-card mb-3">
                <div class="expandable-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <h6 class="mb-0">Change Password</h6>
                    <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
                </div>
                @if (_passwordPanelOpen)
                {
                    <div class="mt-3">
                        <div class="mb-2">
                            <label class="form-label">Current Password</label>
                            <input class="form-control" type="password" @bind="_currentPassword" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">New Password</label>
                            <input class="form-control" type="password" @bind="_newPassword" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Confirm New Password</label>
                            <input class="form-control" type="password" @bind="_confirmPassword" />
                        </div>
                        <button class="btn btn-primary" @onclick="ChangePassword">Update Password</button>
                    </div>
                }
            </div>

            @* Two-Factor *@
            <div class="settings-card mb-3">
                <div class="toggle-row">
                    <div>
                        <label>Two-Factor Authentication</label>
                        <span class="badge ms-2 @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@_twoFactorEnabled"
                               @onchange="e => _twoFactorEnabled = (bool)e.Value!" />
                    </div>
                </div>
                @if (_security?.LastPasswordChange is not null)
                {
                    <small class="text-muted">Last password change: @_security.LastPasswordChange.Value.ToString("MMM dd, yyyy")</small>
                }
            </div>

            @* Active Sessions *@
            <div class="settings-card">
                <h6>Active Sessions</h6>
                <div class="table-responsive">
                    <table class="table table-sm mb-0">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @if (_security is not null)
                            {
                                @foreach (var session in _security.Sessions)
                                {
                                    var isCurrent = session.Id == _security.Sessions.First().Id;
                                    <tr>
                                        <td>@session.Device</td>
                                        <td>@session.Location</td>
                                        <td>@FormatLastActive(session.LastActive)</td>
                                        <td>
                                            @if (isCurrent)
                                            {
                                                <span class="badge bg-info">Current</span>
                                            }
                                            else
                                            {
                                                <button class="btn btn-sm btn-outline-danger"
                                                        @onclick="() => PromptRevokeSession(session)">
                                                    Revoke
                                                </button>
                                            }
                                        </td>
                                    </tr>
                                }
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </section>;
}

@* ───── APPEARANCE ───── *@
@{
    RenderFragment RenderAppearanceSection() =>
        @<section>
            <h4>Appearance</h4>
            <div class="settings-card">
                <div class="mb-3">
                    <label class="form-label fw-semibold">Theme</label>
                    <div class="d-flex gap-3">
                        @foreach (var theme in new[] { "Light", "Dark", "System" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="@($"theme-{theme}")"
                                       checked="@(_editAppearance!.Theme == theme)"
                                       @onchange="() => _editAppearance.Theme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Font Size</label>
                    <div class="d-flex gap-3">
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="@($"fs-{size}")"
                                       checked="@(_editAppearance!.FontSize == size)"
                                       @onchange="() => _editAppearance.FontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Language</label>
                    <select class="form-select" value="@_editAppearance!.Language"
                            @onchange="e => _editAppearance.Language = e.Value!.ToString()!">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                <div class="toggle-row mb-3">
                    <label>Compact Mode</label>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@_editAppearance.CompactMode"
                               @onchange="e => _editAppearance.CompactMode = (bool)e.Value!" />
                    </div>
                </div>

                @* Live preview *@
                <div class="appearance-preview @GetPreviewClasses()">
                    <div class="preview-header">Preview</div>
                    <p class="preview-body">
                        This is how your content will look with the selected settings.
                    </p>
                    <span class="badge bg-primary">Badge</span>
                    <button class="btn btn-sm btn-outline-primary ms-2">Sample Button</button>
                </div>

                <button class="btn btn-primary mt-3" @onclick="SaveAppearance">Save</button>
            </div>
        </section>;
}

@code {
    // ── Navigation ──
    private string ActiveSection { get; set; } = "profile";

    private record SectionInfo(string Key, string Label, string Icon);

    private readonly SectionInfo[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨")
    ];

    // ── State ──
    private bool _loading = true;
    private string? _toastMessage;
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // Profile
    private UserProfile? _savedProfile;
    private ProfileEdit? _editProfile;

    // Notifications
    private EditNotifications? _editNotifications;
    private readonly string[] _allChannels = ["general", "announcements", "marketing", "engineering", "design"];

    // Security
    private SecuritySettings? _security;
    private bool _twoFactorEnabled;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _showConfirmDialog;
    private ActiveSession? _sessionToRevoke;

    // Appearance
    private AppearanceEdit? _editAppearance;
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    // ── Mutable edit models (records are immutable) ──
    private class ProfileEdit
    {
        public string DisplayName { get; set; } = "";
        public string Email { get; set; } = "";
        public string AvatarUrl { get; set; } = "";
        public string Bio { get; set; } = "";

        public static ProfileEdit From(UserProfile p) =>
            new() { DisplayName = p.DisplayName, Email = p.Email, AvatarUrl = p.AvatarUrl, Bio = p.Bio };

        public UserProfile ToRecord() => new(DisplayName, Email, AvatarUrl, Bio);
    }

    private class EditNotifications
    {
        public bool EmailNotifications { get; set; }
        public bool PushNotifications { get; set; }
        public bool WeeklyDigest { get; set; }
        public List<string> MutedChannels { get; set; } = [];

        public static EditNotifications From(NotificationPrefs p) =>
            new()
            {
                EmailNotifications = p.EmailNotifications,
                PushNotifications = p.PushNotifications,
                WeeklyDigest = p.WeeklyDigest,
                MutedChannels = [.. p.MutedChannels]
            };

        public NotificationPrefs ToRecord() => new(EmailNotifications, PushNotifications, WeeklyDigest, MutedChannels);
    }

    private class AppearanceEdit
    {
        public string Theme { get; set; } = "Light";
        public string FontSize { get; set; } = "Medium";
        public string Language { get; set; } = "English";
        public bool CompactMode { get; set; }

        public static AppearanceEdit From(AppearanceSettings s) =>
            new() { Theme = s.Theme, FontSize = s.FontSize, Language = s.Language, CompactMode = s.CompactMode };

        public AppearanceSettings ToRecord() => new(Theme, FontSize, Language, CompactMode);
    }

    // ── Lifecycle ──
    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        _savedProfile = profile;
        _editProfile = ProfileEdit.From(profile);

        var notifs = await SettingsService.GetNotificationPrefsAsync();
        _editNotifications = EditNotifications.From(notifs);

        _security = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _security.TwoFactorEnabled;

        var appearance = await SettingsService.GetAppearanceAsync();
        _editAppearance = AppearanceEdit.From(appearance);

        _loading = false;
    }

    // ── Profile actions ──
    private async Task SaveProfile()
    {
        var record = _editProfile!.ToRecord();
        await SettingsService.SaveProfileAsync(record);
        _savedProfile = record;
        ShowToast("Profile saved successfully.");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
            _editProfile = ProfileEdit.From(_savedProfile);
    }

    // ── Notification actions ──
    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted && !_editNotifications!.MutedChannels.Contains(channel))
            _editNotifications.MutedChannels.Add(channel);
        else if (!muted)
            _editNotifications!.MutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        await SettingsService.SaveNotificationPrefsAsync(_editNotifications!.ToRecord());
        ShowToast("Notification preferences saved.");
    }

    // ── Security actions ──
    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword != _confirmPassword)
        {
            ShowToast("Passwords do not match.", isError: true);
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = _newPassword = _confirmPassword = "";
        _passwordPanelOpen = false;
        ShowToast("Password updated successfully.");
    }

    private void PromptRevokeSession(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showConfirmDialog = true;
    }

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _security = await SettingsService.GetSecuritySettingsAsync();
        }

        _showConfirmDialog = false;
        _sessionToRevoke = null;
        ShowToast("Session revoked.");
    }

    // ── Appearance actions ──
    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        if (_editAppearance!.Theme == "Dark") classes.Add("preview-dark");
        if (_editAppearance.FontSize == "Small") classes.Add("preview-small");
        if (_editAppearance.FontSize == "Large") classes.Add("preview-large");
        if (_editAppearance.CompactMode) classes.Add("preview-compact");
        return string.Join(' ', classes);
    }

    private async Task SaveAppearance()
    {
        await SettingsService.SaveAppearanceAsync(_editAppearance!.ToRecord());
        ShowToast("Appearance settings saved.");
    }

    // ── Helpers ──
    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    private void ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastMessage = message;
        _toastIsError = isError;

        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _ = Task.Run(async () =>
        {
            await Task.Delay(3000, token);
            if (!token.IsCancellationRequested)
            {
                await InvokeAsync(() =>
                {
                    _toastMessage = null;
                    StateHasChanged();
                });
            }
        }, token);
    }
}
